  ('pukao-d592fc58-moex-00132', 'pukao-d592fc58', 'pukao-d592fc58-moex-110-6948958a', 'sub-pukao-d592fc58-01', NULL, 'single_choice', '某國2018年國民所得帳統計資料如下（單位十億元）： 總投資（GrossInvestment）：180、國民所得（NationalIncome）：1,000、淨出口（NetExports）：20、 個人所得（PersonalIncome）：850、民間消費（PrivateConsumption）：700、儲蓄（Saving）：50、 政府支出（GovernmentExpenditure）：200、國內生產淨值（NetDomesticProduct）：1,050。 該國2018年的國內生產毛額（GDP）為何？', '["1,000", "950", "1,100", "1,070"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "420", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
